questions.explanation:
遍历每条消息，对每个位置 i 检查 s[i] 和 s[i+1] 是否组成 6 种文本表情之一。注意循环只到倒数第二个字符，每次匹配两个字符。

```cpp
#include <bits/stdc++.h>
using namespace std;
bool emo(char a, char b) {
    if (a == ':' && b == ')') return 1;
    if (a == ':' && b == '(') return 1;
    if (a == ':' && b == 'D') return 1;
    if (a == ':' && b == 'P') return 1;
    if (a == ';' && b == '(') return 1;
    if (a == ';' && b == 'p') return 1;
    return 0;
}
int main() {
    int n, cnt = 0;
    cin >> n;
    while (n--) {
        string s;
        cin >> s;
        for (int i = 0; i + 1 < s.size(); i++)
            if (emo(s[i], s[i + 1])) cnt++;
    }
    cout << cnt << endl;
    return 0;
}
```

用一个计数数组 cnt[1005] 统计每个数字出现次数，全部读入后遍历找 cnt[i] 为奇数者输出。关键是用数组下标作为计数器。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, x, cnt[1005] = {};
    cin >> n;
    for (int i = 0; i < n; i++) { cin >> x; cnt[x]++; }
    for (int i = 1; i <= 1000; i++)
        if (cnt[i] % 2) { cout << i << endl; break; }
    return 0;
}
```

构建二维前缀和，四重循环枚举所有子矩形，O(1) 计算和取最大值。若最大值 ≤ 0 则输出 0。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, m, a[35][35], s[35][35] = {};
    cin >> n >> m;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++) {
            cin >> a[i][j];
            s[i][j] = s[i-1][j] + s[i][j-1] - s[i-1][j-1] + a[i][j];
        }
    int ans = 0;
    for (int x1 = 1; x1 <= n; x1++)
        for (int y1 = 1; y1 <= m; y1++)
            for (int x2 = x1; x2 <= n; x2++)
                for (int y2 = y1; y2 <= m; y2++) {
                    int sum = s[x2][y2] - s[x1-1][y2] - s[x2][y1-1] + s[x1-1][y1-1];
                    if (sum > ans) ans = sum;
                }
    cout << ans << endl;
    return 0;
}
```

定义结构体存 name 和三关分数 a,b,c。计算最高分 mx=mx3(a,b,c) 和最低分 mn=mn3(a,b,c)。排序先比 mx 降序，再比 mn 降序，最后比 name 升序。

```cpp
#include <bits/stdc++.h>
using namespace std;
struct Team { string nm; int a, b, c, mx, mn; };
int mx3(int x, int y, int z) { return max(x, max(y, z)); }
int mn3(int x, int y, int z) { return min(x, min(y, z)); }
bool cmp(Team x, Team y) {
    if (x.mx != y.mx) return x.mx > y.mx;
    if (x.mn != y.mn) return x.mn > y.mn;
    return x.nm < y.nm;
}
int main() {
    int n;
    cin >> n;
    Team t[1005];
    for (int i = 0; i < n; i++) {
        cin >> t[i].nm >> t[i].a >> t[i].b >> t[i].c;
        t[i].mx = mx3(t[i].a, t[i].b, t[i].c);
        t[i].mn = mn3(t[i].a, t[i].b, t[i].c);
    }
    sort(t, t + n, cmp);
    for (int i = 0; i < n; i++) cout << t[i].nm << endl;
    return 0;
}
```
